    public static WarehouseReceiptCoreExt load(String contractAddress, Client client,
            TransactionManager transactionManager) {
        return new WarehouseReceiptCoreExt(contractAddress, client, transactionManager);
    }

    public static WarehouseReceiptCoreExt load(String contractAddress, Client client) {
        return new WarehouseReceiptCoreExt(contractAddress, client, new ProxySignTransactionManager(client));
    }

    public static WarehouseReceiptCoreExt deploy(Client client, CryptoKeyPair credential,
            String _initialAdmin) throws ContractException {
        @SuppressWarnings("rawtypes")
        byte[] encodedConstructor = FunctionEncoder.encodeConstructor(Arrays.<Type>asList(new org.fisco.bcos.sdk.v3.codec.datatypes.Address(_initialAdmin)));
        WarehouseReceiptCoreExt contract = deploy(WarehouseReceiptCoreExt.class, client, credential, getBinary(client.getCryptoSuite()), getABI(), encodedConstructor, null);
        contract.setTransactionManager(new ProxySignTransactionManager(client));
        return contract;
    }

    public static class PledgeInfo extends DynamicStruct {
        public String loanId;

        public BigInteger pledgeAmount;

        public BigInteger pledgeTime;

        public String pledger;

        public Boolean active;

        public PledgeInfo(Utf8String loanId, Uint256 pledgeAmount, Uint256 pledgeTime,
                Address pledger, Bool active) {
            super(loanId,pledgeAmount,pledgeTime,pledger,active);
            this.loanId = loanId.getValue();
            this.pledgeAmount = pledgeAmount.getValue();
            this.pledgeTime = pledgeTime.getValue();
            this.pledger = pledger.getValue();
            this.active = active.getValue();
        }

        public PledgeInfo(String loanId, BigInteger pledgeAmount, BigInteger pledgeTime,
                String pledger, Boolean active) {
            super(new org.fisco.bcos.sdk.v3.codec.datatypes.Utf8String(loanId),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Uint256(pledgeAmount),new org.fisco.bcos.sdk.v3.codec.datatypes.generated.Uint256(pledgeTime),new org.fisco.bcos.sdk.v3.codec.datatypes.Address(pledger),new org.fisco.bcos.sdk.v3.codec.datatypes.Bool(active));
            this.loanId = loanId;
            this.pledgeAmount = pledgeAmount;
            this.pledgeTime = pledgeTime;
            this.pledger = pledger;
            this.active = active;
        }
    }

